const body = $json.body ?? {};

const message = body.message ?? body.user_message ?? '';
const sessionId = body.sessionId ?? null;
const context = body.context ?? {};

const state = body.state ?? {
  phase: 'idle',
  pending_slot: null,
  booking_intent: false,
};

return [{ json: { message, sessionId, context, state } }];

const message = ($json.message ?? '').toString();
const state = $json.state ?? {};

const confirmRe = /\b(yes|yeah|yep|please|book|confirm|ok|okay|ja|bitte|mach|buche|buchen)\b/i;
const weekdayRe = /(montag|dienstag|mittwoch|donnerstag|freitag|samstag|sonntag|monday|tuesday|wednesday|thursday|friday|saturday|sunday)/i;
const hasWeekday = weekdayRe.test(message);

const confirm_booking = !!state?.pending_slot?.start && !!state?.pending_slot?.end && confirmRe.test(message) && !hasWeekday;

const policy = {
  tz: ($env.AGENT_TZ ?? $env.TZ ?? 'Europe/Berlin').toString(),
  workdays: ($env.AGENT_WORKDAYS ?? '1,2,3,4,5').toString(),
  workStart: ($env.AGENT_WORK_START ?? '09:00').toString(),
  workEnd: ($env.AGENT_WORK_END ?? '17:00').toString(),
  horizonDays: Number($env.AGENT_HORIZON_DAYS ?? 30) || 30,
  durationMinutes: 30,
};

function parseHHMM(value, fallback) {
  const m = value?.toString().trim().match(/^(\d{1,2}):(\d{2})$/);
  if (!m) return fallback;
  const hh = Math.min(23, Math.max(0, Number(m[1])));
  const mm = Math.min(59, Math.max(0, Number(m[2])));
  return { hh, mm };
}

function parseSlotCandidate(text) {
  const lower = text.toLowerCase();
  const weekdayMap = {
    montag: 1,
    dienstag: 2,
    mittwoch: 3,
    donnerstag: 4,
    freitag: 5,
    samstag: 6,
    sonntag: 0,
    monday: 1,
    tuesday: 2,
    wednesday: 3,
    thursday: 4,
    friday: 5,
    saturday: 6,
    sunday: 0,
  };

  const weekdayKey = Object.keys(weekdayMap).find((k) => new RegExp(`\\b${k}\\b`, 'i').test(lower));
  if (!weekdayKey) return null;

  // Supports: "12 o clock", "12 o'clock", "12:30", "12 uhr", "12pm", "12 pm"
  const timeMatch = lower.match(/\\b(\\d{1,2})(?:[:.](\\d{2}))?\\s*(uhr|o\\s*'?clock|am|pm)?\\b/);
  if (!timeMatch) return null;

  let hour = Math.min(23, Math.max(0, Number(timeMatch[1])));
  const minute = timeMatch[2] ? Math.min(59, Math.max(0, Number(timeMatch[2]))) : 0;
  const suffix = (timeMatch[3] || '').replace(/\\s+/g, '');
  if (suffix === 'pm' && hour < 12) hour += 12;
  if (suffix === 'am' && hour === 12) hour = 0;

  const targetDow = weekdayMap[weekdayKey];
  const now = new Date();
  const todayDow = now.getDay();

  let addDays = (targetDow - todayDow + 7) % 7;
  const wantsNext = /\\bnext\\b/i.test(lower);

  const candidate = new Date(now.getFullYear(), now.getMonth(), now.getDate(), hour, minute, 0, 0);
  if (addDays === 0 && candidate.getTime() <= now.getTime()) addDays = 7;
  if (wantsNext && addDays === 0) addDays = 7;
  candidate.setDate(candidate.getDate() + addDays);

  const durationMin = Number(policy.durationMinutes ?? 30) || 30;
  const end = new Date(candidate.getTime() + durationMin * 60_000);
  return {
    start: candidate.toISOString(),
    end: end.toISOString(),
    label: candidate.toLocaleString(),
    confidence: 0.9,
  };
}

const slot_candidate = parseSlotCandidate(message);

// Quick policy validation for candidate (so controller can use it safely)
let slot_candidate_ok = false;
if (slot_candidate) {
  const startDate = new Date(slot_candidate.start);
  const workdays = policy.workdays.split(',').map((s) => Number(s.trim())).filter((n) => Number.isFinite(n));
  const ws = parseHHMM(policy.workStart, { hh: 9, mm: 0 });
  const we = parseHHMM(policy.workEnd, { hh: 17, mm: 0 });
  const startMinutes = startDate.getHours() * 60 + startDate.getMinutes();
  const wsMin = ws.hh * 60 + ws.mm;
  const weMin = we.hh * 60 + we.mm;
  const withinWorkday = !workdays.length || workdays.includes(startDate.getDay());
  const withinHours = startMinutes >= wsMin && startMinutes < weMin;
  slot_candidate_ok = withinWorkday && withinHours;
}

return [{ json: { ...$json, confirm_booking, policy, slot_candidate, slot_candidate_ok } }];

const input = $node["Preprocess + Policy"].json;
const message = (input.message ?? '').toString();
const sessionId = input.sessionId ?? null;
const state = input.state ?? {};
const policy = input.policy ?? {};
const confirm_booking = input.confirm_booking === true;
const slot_candidate = input.slot_candidate ?? null;
const slot_candidate_ok = input.slot_candidate_ok === true;

// OpenAI node output
if ($json?.error?.message) {
  return [{ json: { reply: `LLM Fehler: ${$json.error.message}`, booking_intent: false, do_booking: false, state, sessionId } }];
}

if (!$json || typeof $json !== 'object' || !Array.isArray($json.choices)) {
  // fallback: if we have a good deterministic slot candidate, continue without LLM
  if (slot_candidate && slot_candidate_ok) {
    const newState = { ...state, phase: 'pending_booking', booking_intent: true, pending_slot: { ...slot_candidate, durationMin: policy.durationMinutes ?? 30 } };
    return [{ json: { reply: 'Alles klar. Ich prüfe kurz deinen Termin…', booking_intent: true, do_booking: true, slot: slot_candidate, policy, state: newState, message, sessionId } }];
  }
  return [{ json: { reply: 'LLM ist gerade nicht verfügbar.', booking_intent: false, do_booking: false, state, sessionId } }];
}

const content = $json.choices?.[0]?.message?.content;
let parsed;
try {
  parsed = JSON.parse((content ?? '').toString());
} catch {
  return [{ json: { reply: (content ?? 'LLM returned non-JSON.').toString(), booking_intent: false, do_booking: false, state, sessionId } }];
}

let booking_intent = parsed?.booking_intent === true;
let reply = typeof parsed?.reply === 'string' ? parsed.reply : 'OK';

const state_update = parsed?.state_update && typeof parsed.state_update === 'object' ? parsed.state_update : {};
let newState = { ...state, ...state_update };

// Slot handling
let slot = parsed?.slot ?? null;
if (slot && typeof slot === 'object') {
  const start = typeof slot.start === 'string' ? slot.start : null;
  const end = typeof slot.end === 'string' ? slot.end : null;
  const label = typeof slot.label === 'string' ? slot.label : null;
  const confidence = typeof slot.confidence === 'number' ? slot.confidence : null;
  if (!start || !end) slot = null;
  else slot = { start, end, label: label ?? start, confidence: confidence ?? 0.5 };
}

// Deterministic fallback if LLM didn't extract slot
if (!slot && slot_candidate && slot_candidate_ok) {
  slot = slot_candidate;
  booking_intent = true;
  if (!reply || reply === 'OK') reply = 'Alles klar. Ich prüfe kurz deinen Termin…';
}

newState = { ...newState, booking_intent };

// If user confirmed and we have a pending slot, use it even if LLM left slot null
if (booking_intent && confirm_booking && !slot && newState?.pending_slot?.start && newState?.pending_slot?.end) {
  slot = {
    start: newState.pending_slot.start,
    end: newState.pending_slot.end,
    label: newState.pending_slot.label ?? 'the requested time',
    confidence: 1,
  };
}

// Store pending slot if we have one
if (booking_intent && slot) {
  newState = {
    ...newState,
    phase: 'pending_booking',
    pending_slot: { start: slot.start, end: slot.end, label: slot.label, durationMin: policy.durationMinutes ?? 30 },
  };
}

// Decide if we proceed to tools
const do_booking = booking_intent && !!slot;

return [{ json: { reply, booking_intent, do_booking, slot, policy, state: newState, message, sessionId } }];

const state = $json.state ?? {};
const slot = $json.slot;
const policy = $json.policy ?? {};

if (!slot?.start || !slot?.end) {
  return [{ json: { ...$json, do_booking: false, reply: 'Bitte nenn mir Tag + Uhrzeit (Mo–Fr 09:00–17:00).', state } }];
}

const workdays = (policy.workdays ?? '1,2,3,4,5').toString().split(',').map(s => Number(s.trim())).filter(n => Number.isFinite(n));

function parseHHMM(v, fb){
  const m = v?.toString().trim().match(/^(\d{1,2}):(\d{2})$/);
  if(!m) return fb;
  return {hh: Math.min(23, Math.max(0, Number(m[1]))), mm: Math.min(59, Math.max(0, Number(m[2])))};
}

const ws = parseHHMM(policy.workStart ?? '09:00', {hh:9,mm:0});
const we = parseHHMM(policy.workEnd ?? '17:00', {hh:17,mm:0});
const horizonDays = Math.max(1, Number(policy.horizonDays ?? 30) || 30);

const startDate = new Date(slot.start);
const endDate = new Date(slot.end);

if (!Number.isFinite(startDate.getTime()) || !Number.isFinite(endDate.getTime())) {
  return [{ json: { ...$json, do_booking: false, reply: 'Ich konnte die Uhrzeit nicht lesen. Bitte z.B. "Monday 11:00".', state } }];
}

const now = new Date();
const latest = new Date(now.getTime() + horizonDays*24*60*60_000);
if (startDate.getTime() > latest.getTime()) {
  return [{ json: { ...$json, do_booking: false, reply: `Ich kann nur bis ${horizonDays} Tage im Voraus buchen.`, state } }];
}

if (workdays.length && !workdays.includes(startDate.getDay())) {
  return [{ json: { ...$json, do_booking: false, reply: 'Ich kann nur Mo–Fr buchen. Bitte nenn mir einen Termin unter der Woche.', state } }];
}

const startMinutes = startDate.getHours()*60 + startDate.getMinutes();
const wsMin = ws.hh*60 + ws.mm;
const weMin = we.hh*60 + we.mm;
if (startMinutes < wsMin || startMinutes >= weMin) {
  return [{ json: { ...$json, do_booking: false, reply: `Ich kann nur zwischen ${String(ws.hh).padStart(2,'0')}:${String(ws.mm).padStart(2,'0')} und ${String(we.hh).padStart(2,'0')}:${String(we.mm).padStart(2,'0')} buchen (Mo–Fr).`, state } }];
}

return [{ json: { ...$json, do_booking: true } }];

const state = $node["Controller (Parse/State)"].json.state ?? {};
const slot = $node["Policy Validate Slot"].json.slot;

if ($json?.error || $json?.message?.includes?.('credential') || $json?.name === 'NodeOperationError') {
  return [{ json: { reply: 'Konnte nicht buchen: Google Calendar Credentials/Permissions fehlen.', state, booking_intent: true } }];
}

const eventId = $json?.id;
const newState = { ...state, phase: 'booked', booked_event_id: eventId ?? null, pending_slot: null };

const label = slot?.label ?? slot?.start ?? 'the requested time';
return [{ json: { reply: `Gebucht: ${label} (30min).`, state: newState, booking_intent: true } }];

const state = $node["Controller (Parse/State)"].json.state ?? {};
const slot = $node["Policy Validate Slot"].json.slot;

if ($json?.error || $json?.message?.includes?.('credential') || $json?.name === 'NodeOperationError') {
  return [{ json: { reply: 'Kalender ist noch nicht verbunden (Google Calendar Credentials fehlen).', state, booking_intent: true } }];
}

const label = slot?.label ?? slot?.start ?? 'the requested time';
return [{ json: { reply: `${label} ist leider belegt. Bitte nenn mir eine Alternative (Mo–Fr 09:00–17:00).`, state, booking_intent: true } }];

const reply = $json.reply ?? 'OK';
const state = $json.state ?? {};
const booking_intent = $json.booking_intent ?? state.booking_intent ?? false;

return [{ json: { reply, state, booking_intent } }];
